package tn.esprit.controllers;

import javafx.application.Platform;
import javafx.event.ActionEvent;
import javafx.fxml.FXML;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;
import tn.esprit.services.WebFaceEmbeddingService;

import java.util.List;

/**
 * Controller pour l'enregistrement du visage pendant l'inscription
 * Capture simple via webcam, génère l'embedding, enregistre dans la DB
 */
public class FaceEnrollmentController {

    @FXML private VBox enrollmentContainer;
    @FXML private Label instructionLabel;
    @FXML private Button captureBtn;
    @FXML private Button skipBtn;
    @FXML private Label statusLabel;

    private final WebFaceEmbeddingService embeddingService = new WebFaceEmbeddingService();
    private OnEnrollmentComplete callback;

    public interface OnEnrollmentComplete {
        void onSuccess(String faceEmbedding);
        void onSkip();
    }

    @FXML
    private void initialize() {
        if (instructionLabel != null) {
            instructionLabel.setText("Positionnez votre visage face à la caméra. Appuyez sur 'Capturer' quand prêt.");
        }
        if (captureBtn != null) {
            captureBtn.setText("Capturer le visage");
        }
        if (skipBtn != null) {
            skipBtn.setText("Passer");
        }
    }

    @FXML
    private void handleCapture(ActionEvent event) {
        if (captureBtn != null) {
            captureBtn.setDisable(true);
            captureBtn.setText("Capture en cours...");
        }

        if (statusLabel != null) {
            statusLabel.setText("Initialisation caméra...");
            statusLabel.setStyle("-fx-text-fill: #3b82f6;");
        }

        embeddingService.captureEmbedding(null)
                .thenAccept(embedding -> Platform.runLater(() -> {
                    String embeddingJson = serializeEmbedding(embedding);

                    if (statusLabel != null) {
                        statusLabel.setText("Visage capturé avec succès!");
                        statusLabel.setStyle("-fx-text-fill: #16a34a;");
                    }

                    // Appeler le callback de succès
                    if (callback != null) {
                        callback.onSuccess(embeddingJson);
                    }
                }))
                .exceptionally(ex -> {
                    String error = ex.getMessage() == null ? "Erreur inconnue" : ex.getMessage();
                    Platform.runLater(() -> {
                        if (statusLabel != null) {
                            statusLabel.setText("Erreur: " + error);
                            statusLabel.setStyle("-fx-text-fill: #dc2626;");
                        }
                        if (captureBtn != null) {
                            captureBtn.setDisable(false);
                            captureBtn.setText("Réessayer");
                        }
                    });
                    return null;
                });
    }

    @FXML
    private void handleSkip(ActionEvent event) {
        if (callback != null) {
            callback.onSkip();
        }
    }

    public void setOnEnrollmentComplete(OnEnrollmentComplete callback) {
        this.callback = callback;
    }

    private String serializeEmbedding(List<Double> embedding) {
        if (embedding == null || embedding.isEmpty()) {
            return "[]";
        }

        StringBuilder sb = new StringBuilder("[");
        for (int i = 0; i < embedding.size(); i++) {
            if (i > 0) sb.append(",");
            sb.append(embedding.get(i));
        }
        sb.append("]");

        return sb.toString();
    }
}

package tn.esprit.controllers;

import javafx.application.Platform;
import javafx.event.ActionEvent;
import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
