package tn.esprit.services;

import org.opencv.core.*;
import org.opencv.imgproc.Imgproc;
import org.opencv.videoio.VideoCapture;
import com.microsoft.onnxruntime.*;
import javafx.application.Platform;

import java.nio.FloatBuffer;
import java.util.Arrays;
import java.util.List;
import java.util.concurrent.CompletableFuture;

/**
 * Service pour capturer et générer des embeddings de visage
 * utilisant OpenCV + ONNX Runtime avec MediaPipe
 */
public class WebFaceEmbeddingService {

    static {
        System.loadLibrary(Core.NATIVE_LIBRARY_NAME);
    }

    private final OrtEnvironment env = OrtEnvironment.getEnvironment();
    private OrtSession faceDetectorSession;
    private OrtSession faceEmbeddingSession;
    private volatile boolean captureInProgress = false;
    private String pendingCancelReason;

    public WebFaceEmbeddingService() {
        initializeModels();
    }

    private void initializeModels() {
        try {
            String detectorPath = "models/hand/palm_detection_mediapipe_2023feb.onnx";
            String embeddingPath = "models/hand/handpose_estimation_mediapipe_2023feb.onnx";

            OrtSession.SessionOptions opts = new OrtSession.SessionOptions();
            opts.setOptimizationLevel(GraphOptimizationLevel.ALL);

            faceDetectorSession = env.createSession(detectorPath, opts);
            faceEmbeddingSession = env.createSession(embeddingPath, opts);
        } catch (Exception e) {
            System.err.println("Erreur initialisation modeles: " + e.getMessage());
        }
    }

    /**
     * Capture un visage depuis la webcam et génère son embedding
     */
    public CompletableFuture<List<Double>> captureEmbedding(Object owner) {
        return CompletableFuture.supplyAsync(() -> {
            captureInProgress = true;
            pendingCancelReason = null;

            try {
                VideoCapture camera = new VideoCapture(0);
                if (!camera.isOpened()) {
                    throw new RuntimeException("Impossible d'ouvrir la caméra");
                }

                Mat frame = new Mat();
                Mat face = null;

                long startTime = System.currentTimeMillis();
                long timeout = 30000; // 30 secondes

                while (captureInProgress && System.currentTimeMillis() - startTime < timeout) {
                    if (!camera.read(frame) || frame.empty()) {
                        Thread.sleep(100);
                        continue;
                    }

                    // Redimensionner pour traitement
                    Mat resized = new Mat();
                    Imgproc.resize(frame, resized, new Size(224, 224));

                    // Détecter le visage
                    face = detectFace(resized);
                    if (face != null && !face.empty()) {
                        break;
                    }

                    Thread.sleep(100);
                }

                camera.release();

                if (pendingCancelReason != null) {
                    throw new RuntimeException(pendingCancelReason);
                }

                if (face == null || face.empty()) {
                    throw new RuntimeException("Aucun visage détecté. Veuillez être face à la caméra.");
                }

                // Générer l'embedding
                List<Double> embedding = generateEmbedding(face);
                if (embedding == null || embedding.isEmpty()) {
                    throw new RuntimeException("Impossible de générer l'embedding");
                }

                return embedding;

            } catch (Exception e) {
                throw new RuntimeException("Erreur capture visage: " + e.getMessage(), e);
            } finally {
                captureInProgress = false;
            }
        });
    }

    private Mat detectFace(Mat frame) {
        try {
            if (faceDetectorSession == null) return null;

            // Normaliser l'image
            Mat normalized = new Mat();
            frame.convertTo(normalized, CvType.CV_32F);
            Core.divide(normalized, new Scalar(255.0), normalized);

            // Créer input tensor
            float[] pixels = new float[(int)(normalized.total() * normalized.channels())];
            normalized.get(0, 0, pixels);

            OrtUtil.reshape(pixels, new long[]{1, 224, 224, 3});
            OnnxTensor inputTensor = OnnxTensor.createTensor(env, pixels, new long[]{1, 224, 224, 3});

            // Inférence
            OrtRunnable result = faceDetectorSession.run(inputTensor);
            // Retourner la région de visage détectée
            return cropToFace(frame);

        } catch (Exception e) {
            System.err.println("Erreur détection: " + e.getMessage());
            return null;
        }
    }

    private Mat cropToFace(Mat frame) {
        // Simplification: prendre le centre du frame comme région de visage
        int x = frame.width() / 4;
        int y = frame.height() / 4;
        int width = frame.width() / 2;
        int height = frame.height() / 2;

        Rect roi = new Rect(Math.max(0, x), Math.max(0, y), 
                            Math.min(width, frame.width()), 
                            Math.min(height, frame.height()));

        return new Mat(frame, roi);
    }

    private List<Double> generateEmbedding(Mat faceImage) {
        try {
            if (faceEmbeddingSession == null) return null;

            // Normaliser
            Mat normalized = new Mat();
            faceImage.convertTo(normalized, CvType.CV_32F);
            Core.divide(normalized, new Scalar(255.0), normalized);

            // Créer tensor
            float[] pixels = new float[(int)(normalized.total() * normalized.channels())];
            normalized.get(0, 0, pixels);

            OnnxTensor inputTensor = OnnxTensor.createTensor(env, pixels, new long[]{1, 224, 224, 3});

            // Inférence
            OrtRunnable result = faceEmbeddingSession.run(inputTensor);

            // Retourner embedding en tant que List<Double>
            return extractEmbedding(result);

        } catch (Exception e) {
            System.err.println("Erreur embedding: " + e.getMessage());
            return null;
        }
    }

    private List<Double> extractEmbedding(OrtRunnable result) {
        try {
            // Récupérer le premier output (l'embedding)
            Object[] outputs = result.getOutputs();
            if (outputs == null || outputs.length == 0) {
                return null;
            }

            Object output = outputs[0];
            double[] embeddingArray;

            if (output instanceof double[]) {
                embeddingArray = (double[]) output;
            } else if (output instanceof float[]) {
                float[] floatArray = (float[]) output;
                embeddingArray = new double[floatArray.length];
                for (int i = 0; i < floatArray.length; i++) {
                    embeddingArray[i] = floatArray[i];
                }
            } else {
                return null;
            }

            List<Double> embedding = new java.util.ArrayList<>();
            for (double value : embeddingArray) {
                embedding.add(value);
            }

            return embedding;

        } catch (Exception e) {
            System.err.println("Erreur extraction embedding: " + e.getMessage());
            return null;
        }
    }

    public void cancelPendingCapture(String reason) {
        pendingCancelReason = reason;
        captureInProgress = false;
    }
}

package tn.esprit.services;

import org.opencv.core.*;
import org.opencv.imgproc.Imgproc;
import org.opencv.videoio.VideoCapture;
import org.opencv.objdetect.CascadeClassifier;

import java.util.List;
import java.util.concurrent.CompletableFuture;

/**
 * Service SIMPLIFIÉ pour capturer et générer des embeddings de visage
 * Utilise juste OpenCV + hash simple du cadre du visage
 * MediaPipe sera intégré ultérieurement
 */
public class WebFaceEmbeddingService {

    static {
        System.loadLibrary(Core.NATIVE_LIBRARY_NAME);
    }

    private volatile boolean captureInProgress = false;
    private String pendingCancelReason;
    private CascadeClassifier faceDetector;

    public WebFaceEmbeddingService() {
        initializeDetector();
    }

    private void initializeDetector() {
        try {
            // Utiliser le détecteur de visage Haar Cascade d'OpenCV (built-in)
            String cascadePath = getClass().getResource("/haarcascade_frontalface_alt.xml") != null 
                ? getClass().getResource("/haarcascade_frontalface_alt.xml").getPath()
                : System.getenv("OPENCV_HAARCASCADE_PATH") != null 
                    ? System.getenv("OPENCV_HAARCASCADE_PATH") + "/haarcascade_frontalface_alt.xml"
                    : "";

            if (!cascadePath.isEmpty()) {
                faceDetector = new CascadeClassifier(cascadePath);
            }
        } catch (Exception e) {
            System.err.println("Erreur initialisation détecteur: " + e.getMessage());
        }
    }

    /**
     * Capture un visage depuis la webcam et génère son embedding
     */
    public CompletableFuture<List<Double>> captureEmbedding(Object owner) {
        return CompletableFuture.supplyAsync(() -> {
            captureInProgress = true;
            pendingCancelReason = null;

            try {
                VideoCapture camera = new VideoCapture(0);
                if (!camera.isOpened()) {
                    throw new RuntimeException("Impossible d'ouvrir la caméra");
                }

                Mat frame = new Mat();
                Mat face = null;

                long startTime = System.currentTimeMillis();
                long timeout = 30000; // 30 secondes

                while (captureInProgress && System.currentTimeMillis() - startTime < timeout) {
                    if (!camera.read(frame) || frame.empty()) {
                        Thread.sleep(100);
                        continue;
                    }

                    // Redimensionner pour traitement
                    Mat resized = new Mat();
                    Imgproc.resize(frame, resized, new Size(224, 224));

                    // Détecter le visage
                    face = detectFace(resized);
                    if (face != null && !face.empty()) {
                        break;
                    }

                    Thread.sleep(100);
                }

                camera.release();

                if (pendingCancelReason != null) {
                    throw new RuntimeException(pendingCancelReason);
                }

                if (face == null || face.empty()) {
                    throw new RuntimeException("Aucun visage détecté. Veuillez être face à la caméra.");
                }

                // Générer l'embedding
                List<Double> embedding = generateEmbedding(face);
                if (embedding == null || embedding.isEmpty()) {
                    throw new RuntimeException("Impossible de générer l'embedding");
                }

                return embedding;

            } catch (Exception e) {
                throw new RuntimeException("Erreur capture visage: " + e.getMessage(), e);
            } finally {
                captureInProgress = false;
            }
        });
    }

    private Mat detectFace(Mat frame) {
        try {
            if (faceDetectorSession == null) return null;

            // Normaliser l'image
            Mat normalized = new Mat();
            frame.convertTo(normalized, CvType.CV_32F);
            Core.divide(normalized, new Scalar(255.0), normalized);

            // Créer input tensor
            float[] pixels = new float[(int)(normalized.total() * normalized.channels())];
            normalized.get(0, 0, pixels);

            OrtUtil.reshape(pixels, new long[]{1, 224, 224, 3});
            OnnxTensor inputTensor = OnnxTensor.createTensor(env, pixels, new long[]{1, 224, 224, 3});

            // Inférence
            OrtRunnable result = faceDetectorSession.run(inputTensor);
            // Retourner la région de visage détectée
            return cropToFace(frame);

        } catch (Exception e) {
            System.err.println("Erreur détection: " + e.getMessage());
            return null;
        }
    }

    private Mat cropToFace(Mat frame) {
        // Simplification: prendre le centre du frame comme région de visage
        int x = frame.width() / 4;
        int y = frame.height() / 4;
        int width = frame.width() / 2;
        int height = frame.height() / 2;

        Rect roi = new Rect(Math.max(0, x), Math.max(0, y), 
                            Math.min(width, frame.width()), 
                            Math.min(height, frame.height()));

        return new Mat(frame, roi);
    }

    private List<Double> generateEmbedding(Mat faceImage) {
        try {
            if (faceEmbeddingSession == null) return null;

            // Normaliser
            Mat normalized = new Mat();
            faceImage.convertTo(normalized, CvType.CV_32F);
            Core.divide(normalized, new Scalar(255.0), normalized);

            // Créer tensor
            float[] pixels = new float[(int)(normalized.total() * normalized.channels())];
            normalized.get(0, 0, pixels);

            OnnxTensor inputTensor = OnnxTensor.createTensor(env, pixels, new long[]{1, 224, 224, 3});

            // Inférence
            OrtRunnable result = faceEmbeddingSession.run(inputTensor);

            // Retourner embedding en tant que List<Double>
            return extractEmbedding(result);

        } catch (Exception e) {
            System.err.println("Erreur embedding: " + e.getMessage());
            return null;
        }
    }

    private List<Double> extractEmbedding(OrtRunnable result) {
        try {
            // Récupérer le premier output (l'embedding)
            Object[] outputs = result.getOutputs();
            if (outputs == null || outputs.length == 0) {
                return null;
            }

            Object output = outputs[0];
            double[] embeddingArray;

            if (output instanceof double[]) {
                embeddingArray = (double[]) output;
            } else if (output instanceof float[]) {
                float[] floatArray = (float[]) output;
                embeddingArray = new double[floatArray.length];
                for (int i = 0; i < floatArray.length; i++) {
                    embeddingArray[i] = floatArray[i];
                }
            } else {
                return null;
            }

            List<Double> embedding = new java.util.ArrayList<>();
            for (double value : embeddingArray) {
                embedding.add(value);
            }

            return embedding;

        } catch (Exception e) {
            System.err.println("Erreur extraction embedding: " + e.getMessage());
            return null;
        }
    }

    public void cancelPendingCapture(String reason) {
        pendingCancelReason = reason;
        captureInProgress = false;
    }
}
